import sys

def solve(data: str) -> str:
    n = int(data.strip())
    def factorial(value: int) -> int:
        if value == 0:
            return 1
        return value * factorial(value - 1)
    return str(factorial(n))

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
